import {DeltaInsert, deltaToString, EditableBlockSchema} from "../../core";
import {ICodeBlockModel} from "./type";
import {CodeBlock} from "./code.block";

export const CodeBlockSchema: EditableBlockSchema<ICodeBlockModel['props']> = {
  flavour: 'code',
  nodeType: 'editable',
  render: CodeBlock,
  icon: 'bf_icon bf_daimakuai',
  svgIcon: 'bf_daimakuai1',
  label: '代码块',
  onCreate: (deltas: DeltaInsert[]) => {
    return {
      props: () => ({
        lang: 'javascript',
        indent: 0
      }),
      children: deltas?.length ? [{
        insert: deltaToString(deltas),
      }] : []
    }
  }
}
